import {
  ArrowUpRight,
  BarChart3,
  Bell,
  Building2,
  CheckCircle2,
  Clock3,
  MapPin,
  MessageCircle,
  Phone,
  Search,
  ShieldCheck,
  Star,
  UsersRound
} from "lucide-react";
import { businesses, inboxItems, metrics, qaChecks, rubricFlows } from "@/lib/data";
import type { BusinessStatus } from "@/lib/types";

const statusLabels: Record<BusinessStatus, string> = {
  discovery: "Descubrimiento",
  diagnosed: "Diagnosticado",
  contacted: "Contactado",
  active: "Cliente activo"
};

export default function Home() {
  const topOpportunities = businesses
    .slice()
    .sort((a, b) => b.opportunityScore - a.opportunityScore)
    .slice(0, 4);

  return (
    <main className="shell">
      <aside className="sidebar" aria-label="Navegacion principal">
        <div className="brand">
          <div className="brandMark">BO</div>
          <div>
            <strong>Barrio OS</strong>
            <span>Operacion comercial local</span>
          </div>
        </div>

        <nav className="nav">
          <a href="#dashboard">
            <BarChart3 size={18} />
            Panel
          </a>
          <a href="#descubrimiento">
            <Search size={18} />
            Descubrimiento
          </a>
          <a href="#inbox">
            <MessageCircle size={18} />
            Inbox
          </a>
          <a href="#google">
            <ShieldCheck size={18} />
            GBP autorizado
          </a>
        </nav>

        <div className="sidebarNote">
          <span>QA</span>
          <strong>Demo con datos semilla</strong>
          <p>Lista para validar flujos sin conectar fuentes reales ni credenciales.</p>
        </div>
      </aside>

      <section className="workspace" id="dashboard">
        <header className="topbar">
          <div>
            <p className="eyebrow">Sistema Operativo para Negocios de Barrio</p>
            <h1>Captar, responder y convertir consultas locales.</h1>
          </div>
          <button className="primaryButton" type="button">
            <MessageCircle size={18} />
            Abrir WhatsApp
          </button>
        </header>

        <section className="metricsGrid" aria-label="Metricas principales">
          {metrics.map((metric) => (
            <article className="metricCard" key={metric.label}>
              <span>{metric.label}</span>
              <strong>{metric.value}</strong>
              <small>{metric.delta}</small>
            </article>
          ))}
        </section>

        <section className="split">
          <div className="panel" id="descubrimiento">
            <div className="panelHeader">
              <div>
                <p className="eyebrow">Prospeccion propia</p>
                <h2>Oportunidades detectadas</h2>
              </div>
              <button className="iconButton" type="button" aria-label="Abrir prospeccion">
                <ArrowUpRight size={18} />
              </button>
            </div>

            <div className="businessList">
              {topOpportunities.map((business) => (
                <article className="businessRow" key={business.id}>
                  <div className="score" aria-label={`Score ${business.opportunityScore}`}>
                    {business.opportunityScore}
                  </div>
                  <div className="businessBody">
                    <div className="rowBetween">
                      <strong>{business.name}</strong>
                      <span className={`status ${business.status}`}>{statusLabels[business.status]}</span>
                    </div>
                    <p>
                      {business.category} en {business.neighborhood}
                    </p>
                    <div className="signals">
                      {business.signals.map((signal) => (
                        <span key={signal}>{signal}</span>
                      ))}
                    </div>
                  </div>
                </article>
              ))}
            </div>
          </div>

          <div className="panel">
            <div className="panelHeader">
              <div>
                <p className="eyebrow">Diagnostico local</p>
                <h2>Perdidas comerciales visibles</h2>
              </div>
              <Building2 size={20} />
            </div>

            <div className="diagnosticGrid">
              <DiagnosticItem icon={<Phone size={18} />} label="Telefono visible" value="63%" />
              <DiagnosticItem icon={<MessageCircle size={18} />} label="WhatsApp directo" value="41%" />
              <DiagnosticItem icon={<Clock3 size={18} />} label="Horarios claros" value="54%" />
              <DiagnosticItem icon={<Star size={18} />} label="Resenias recientes" value="28%" />
            </div>
          </div>
        </section>

        <section className="split">
          <div className="panel" id="inbox">
            <div className="panelHeader">
              <div>
                <p className="eyebrow">Inbox operativo</p>
                <h2>Consultas para seguimiento</h2>
              </div>
              <Bell size={20} />
            </div>

            <div className="inboxList">
              {inboxItems.map((item) => (
                <article className="inboxItem" key={item.id}>
                  <div>
                    <strong>{item.customer}</strong>
                    <p>{item.message}</p>
                  </div>
                  <span>{item.stage}</span>
                </article>
              ))}
            </div>
          </div>

          <div className="panel">
            <div className="panelHeader">
              <div>
                <p className="eyebrow">Por rubro</p>
                <h2>Flujos listos para operar</h2>
              </div>
              <UsersRound size={20} />
            </div>

            <div className="flowList">
              {rubricFlows.map((flow) => (
                <article className="flowItem" key={flow.category}>
                  <MapPin size={18} />
                  <div>
                    <strong>{flow.category}</strong>
                    <p>{flow.flow}</p>
                  </div>
                </article>
              ))}
            </div>
          </div>
        </section>

        <section className="band" id="google">
          <div>
            <p className="eyebrow">Google Business Profile</p>
            <h2>Separacion tecnica obligatoria</h2>
            <p>
              La API oficial no se usa para descubrir negocios de terceros. La prospeccion se apoya
              en fuentes publicas y relevamiento propio. La integracion con Google Business Profile
              comienza despues de que el cliente autoriza gestionar su perfil.
            </p>
          </div>
          <div className="qaList">
            {qaChecks.map((check) => (
              <div className="qaItem" key={check}>
                <CheckCircle2 size={18} />
                <span>{check}</span>
              </div>
            ))}
          </div>
        </section>
      </section>
    </main>
  );
}

function DiagnosticItem({
  icon,
  label,
  value
}: {
  icon: React.ReactNode;
  label: string;
  value: string;
}) {
  return (
    <article className="diagnosticItem">
      <div>{icon}</div>
      <span>{label}</span>
      <strong>{value}</strong>
    </article>
  );
}
